query.sparql:
ASK {
  wd:Q4205826 wdt:P451 ?partner1.
  wd:Q4463198 wdt:P451 ?partner2.
  FILTER(?partner1 != ?partner2)
}

ASK {
  ?founder wdt:P31 wd:Q33999;  # instance of human
          wdt:P102 wd:Q200202;  # member of political party (National People's Congress)
          wdt:P199 wd:Q214;  # has organizational division (Tencent)
          wdt:P210 ?partyChief.  # party chief representative
}

SELECT ?answer WHERE {
  ?author wdt:P50 wd:Q100000;  # Hunter x Hunter's author
         wdt:P9687 ?givenNames.
  ?work wdt:P50 ?author;
        wdt:P1433 wd:Q123456;  # Replace with the correct publication entity
        wdt:P2679 ?foreword.
  FILTER(CONTAINS(LCASE(?answer), "middle school student"))
}

SELECT ?answer WHERE {
  ?work wdt:P50 ?author.
  ?work wdt:P6333 ?series.
  FILTER(?series != wd:Q123456)  # Replace wd:Q123456 with the actual entity ID for the witcher series
}

ASK {
  ?person1 wdt:P31 wd:Q5;
           wdt:P19 ?birthPlace1.
  ?person2 wdt:P31 wd:Q5;
           wdt:P19 ?birthPlace2.
  VALUES ?person1 { wd:Q12345678 }  # Brooke Raboutou's identifier
  VALUES ?person2 { wd:Q87654321 }  # Colin Duffy's identifier
  FILTER(?birthPlace1 = ?birthPlace2)
}
